<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <title>PDF Extractor Check</title>
  <style>
    body { font-family: monospace; margin: 2em; }
    pre { background: #eee; padding: 1em; white-space: pre-wrap; }
  </style>
</head>
<body>
  <h1>PDF Extractor Manual Check</h1>
  <input type="file" id="filePicker" accept=".pdf" />
  <button id="submitBtn">Extract</button>
  <h2>Result:</h2>
  <pre id="output">No result yet.</pre>
  <script>
    document.getElementById('submitBtn').addEventListener('click', async () => {
      const fileInput = document.getElementById('filePicker');
      if (!fileInput.files.length) { alert('Pick a PDF first'); return; }
      const formData = new FormData();
      formData.append('file', fileInput.files[0]);
      const output = document.getElementById('output');
      output.textContent = 'Processing...';
      try {
        const resp = await fetch('/extract', { method: 'POST', body: formData });
        const json = await resp.json();
        output.textContent = JSON.stringify(json, null, 2);
      } catch (err) {
        output.textContent = 'Error: ' + err.message;
      }
    });
  </script>
</body>
</html>
HTMLEOF
